<?php
 namespace WPAICG\ContentWriter\Ajax\Actions\Shared; use WPAICG\ContentWriter\Prompt\AIPKit_Content_Writer_System_Instruction_Builder; use WPAICG\ContentWriter\Prompt\AIPKit_Content_Writer_User_Prompt_Builder; use WP_Error; if (!defined('ABSPATH')) { exit; } function build_prompts_logic(array $validated_params): array|WP_Error { if (!class_exists(AIPKit_Content_Writer_System_Instruction_Builder::class) || !class_exists(AIPKit_Content_Writer_User_Prompt_Builder::class)) { return new WP_Error('dependency_missing', 'Content writer prompt builders are unavailable.'); } $system_instruction = AIPKit_Content_Writer_System_Instruction_Builder::build($validated_params); $user_prompt_template = AIPKit_Content_Writer_User_Prompt_Builder::build($validated_params); if (empty($user_prompt_template)) { return new WP_Error('missing_prompt', 'Content Prompt cannot be empty.', ['status' => 400]); } $final_title_for_prompt = $validated_params['content_title'] ?? 'AI Generated Content'; $final_keywords = !empty($validated_params['inline_keywords']) ? $validated_params['inline_keywords'] : ($validated_params['content_keywords'] ?? ''); $rss_description = $validated_params['rss_description'] ?? ''; $url_content_context = $validated_params['url_content_context'] ?? ''; $source_url = $validated_params['source_url'] ?? ''; $user_prompt = str_replace('{topic}', $final_title_for_prompt, $user_prompt_template); $user_prompt = str_replace('{keywords}', $final_keywords, $user_prompt); $user_prompt = str_replace('{description}', $rss_description, $user_prompt); $user_prompt = str_replace('{url_content}', $url_content_context, $user_prompt); $user_prompt = str_replace('{source_url}', $source_url, $user_prompt); return [ 'system_instruction' => $system_instruction, 'user_prompt' => $user_prompt, ]; } 